################################
# SIGNAL
#

# Common value
SYS_INFO_SIG_TYPE='<item key="sys.info.sig_type"			type="BOOL"     min="0" max="1" val="0" />'

# Individual value
case "$SIGNAL" in
	"PAL" )
		SYS_INFO_SIG_TYPE='<item key="sys.info.sig_type"			type="BOOL"     min="0" max="1" val="1" />'
	;;
esac




