NF_SYSDB_PART1=(
'<nf_sysdb>'
'<sys>'
'<item key="sys.test.string"				type="STRING" 	min="4" max="8" val="ABCD" />'
'<item key="sys.test.uint"				type="UINT" 	min="0" max="9999" val="123" />'
'<item key="sys.test.int"				type="INT"	 	min="-9999" max="9999" val="-2" />'
'<item key="sys.test.bool"				type="BOOL" 	min="0" max="1" val="1" />'

"$SYS_INIT_SEQURINET_ENABLE"
'<item key="sys.info.sysid"				type="STRING" 	min="0" max="64" val="SYSTEMID" />'
'<item key="sys.info.vendor"			type="STRING" 	min="0" max="32" val="'$VENDOR'" />'
"$SYS_INFO_MODEL"
"$SYS_INFO_HUBVER1"
"$SYS_INFO_HUBVER2"
"$SYS_INFO_HUBVER3"
'<item key="sys.info.hwver"				type="STRING" 	min="0" max="64" val="HARDWARE ID" />'
'<item key="sys.info.fpgaver"		    type="STRING" 	min="0" max="64" val="" />'
'<item key="sys.info.ublver"				type="STRING" 	min="0" max="64" val="" />'
'<item key="sys.info.ubootver"			type="STRING" 	min="0" max="64" val="" />'
'<item key="sys.info.kernelver"			type="STRING" 	min="0" max="64" val="" />'
'<item key="sys.info.panel_type"			type="STRING" 	min="0" max="64" val="" />'
'<item key="sys.info.rc_type"			type="STRING" 	min="0" max="64" val="" />'
'<item key="sys.info.mac"				type="STRING" 	min="12" max="12" val="000000000000" />'
'<item key="sys.info.mac_colon"         type="STRING"   min="17" max="17" val="00:00:00:00:00:00" />'
